-- RX Team — Етап 45 (чіткіші символи: жирніша обводка ~4, простіші форми, крупніший символ).
-- Виконати в Supabase → SQL Editor ПІСЛЯ etap44.sql. Ідемпотентно (UPDATE, base64 без лапок).
--
-- Перемальовано центральні символи для читабельності: обводка ~4 (було ~2.4), прибрано дрібні
-- деталі (ціль без середнього кільця, щит зі зіркою, 3 промені сонця), символ ×1.22, вінок до краю.
-- Принцип незмінний: 1 тема = 1 основа, різниця лише в металі. bmw_01 НЕ чіпаємо.
-- Джерело: assets/achievement-icons/<code>.svg.

update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'first_contact';
update achievements set thumbnail_svg = 'data:image/svg+xml;base64,' where code = 'deploy_10';
